// packages/database/src/db/schema/document-segment.ts
// Drizzle table: documentSegment (generated by scripts/split-schema.ts)

import { createId } from '@paralleldrive/cuid2'
import { customType } from 'drizzle-orm/pg-core'
import {
  type AnyPgColumn,
  boolean,
  index,
  indexStatus,
  integer,
  jsonb,
  pgTable,
  sql,
  text,
  timestamp,
  vector,
} from './_shared'

import { Document } from './document'
import { Organization } from './organization'

/** Custom tsvector type for PostgreSQL full-text search (generated column) */
const tsvectorGenerated = customType<{ data: string }>({
  dataType() {
    return `tsvector GENERATED ALWAYS AS (to_tsvector('english', content)) STORED`
  },
})

/** Drizzle table for documentSegment */
export const DocumentSegment = pgTable(
  'DocumentSegment',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    content: text().notNull(),
    position: integer().notNull(),
    startOffset: integer().notNull(),
    endOffset: integer().notNull(),
    tokenCount: integer().notNull(),

    // Multi-dimension embedding columns (supports different embedding model dimensions)
    embedding_512: vector({ dimensions: 512 }),
    embedding_768: vector({ dimensions: 768 }),
    embedding_1024: vector({ dimensions: 1024 }),
    embedding_1536: vector({ dimensions: 1536 }),
    embedding_3072: vector({ dimensions: 3072 }),

    embeddingModel: text(),
    embeddingDimension: integer(),
    metadata: jsonb(),
    createdAt: timestamp({ precision: 3 }).defaultNow().notNull(),
    updatedAt: timestamp({ precision: 3 }).notNull(),
    documentId: text()
      .notNull()
      .references((): AnyPgColumn => Document.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    organizationId: text()
      .notNull()
      .references((): AnyPgColumn => Organization.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    enabled: boolean().default(true).notNull(),
    indexStatus: indexStatus().default('PENDING').notNull(),
    searchMetadata: jsonb(),

    // Stored generated column for full-text search (auto-computed from content)
    searchVector: tsvectorGenerated('searchVector'),
  },
  (table) => [
    index('DocumentSegment_documentId_idx').using('btree', table.documentId.asc().nullsLast()),
    index('DocumentSegment_organizationId_idx').using(
      'btree',
      table.organizationId.asc().nullsLast()
    ),
    index('DocumentSegment_position_idx').using('btree', table.position.asc().nullsLast()),

    // Multi-dimension embedding HNSW indexes with partial filtering
    index('idx_embedding_512_hnsw')
      .using('hnsw', table.embedding_512.op('vector_cosine_ops'))
      .where(
        sql`(embedding_512 IS NOT NULL AND enabled = true AND "indexStatus" = 'INDEXED'::"IndexStatus")`
      )
      .with({ m: '16', ef_construction: '64' }),

    index('idx_embedding_768_hnsw')
      .using('hnsw', table.embedding_768.op('vector_cosine_ops'))
      .where(
        sql`(embedding_768 IS NOT NULL AND enabled = true AND "indexStatus" = 'INDEXED'::"IndexStatus")`
      )
      .with({ m: '16', ef_construction: '64' }),

    index('idx_embedding_1024_hnsw')
      .using('hnsw', table.embedding_1024.op('vector_cosine_ops'))
      .where(
        sql`(embedding_1024 IS NOT NULL AND enabled = true AND "indexStatus" = 'INDEXED'::"IndexStatus")`
      )
      .with({ m: '16', ef_construction: '64' }),

    index('idx_embedding_1536_hnsw')
      .using('hnsw', table.embedding_1536.op('vector_cosine_ops'))
      .where(
        sql`(embedding_1536 IS NOT NULL AND enabled = true AND "indexStatus" = 'INDEXED'::"IndexStatus")`
      )
      .with({ m: '16', ef_construction: '64' }),

    // NOTE: embedding_3072 has no index (pgvector max indexed dimension is 2000)
    // Queries on 3072-dimension embeddings will use sequential scan

    // GIN index on stored searchVector column for fast full-text search
    index('idx_document_segment_search_vector').using('gin', table.searchVector),

    index('idx_document_segment_dataset_filter')
      .using('btree', table.documentId.asc().nullsLast())
      .where(sql`((enabled = true) AND ("indexStatus" = 'INDEXED'::"IndexStatus"))`),
  ]
)
